SELECT user_id, click_time
FROM click_logs
WHERE click_time LIKE '2023-05-01%';

SELECT mode_name
FROM selection_modes
WHERE is_default = 1;

SELECT user_id, COUNT(*) AS total_clicks
FROM click_logs
GROUP BY user_id;

SELECT COUNT(*) AS single_click_count
FROM click_logs
WHERE user_id = 1 AND click_type = 'single';
